import boto3

def manage_sns_subscriptions():
    """
    Manages SNS subscriptions by accepting user input for endpoints
    and creating subscriptions without validation.
    """
    sns_client = boto3.client('sns')

    topic_arn = input("Enter the SNS Topic ARN: ")

    while True:
        endpoint = input("Enter the subscription endpoint URL (or 'done' to finish): ")
        if endpoint.lower() == 'done':
            break

        if not endpoint:
            print("Endpoint cannot be empty. Please try again.")
            continue

        try:
            response = sns_client.subscribe(
                TopicArn=topic_arn,
                Protocol='https',  # Assuming HTTPS for webhook endpoints
                Endpoint=endpoint,
                ReturnSubscriptionArn=True
            )
            print(f"Subscription request sent for endpoint: {endpoint}")
            print(f"Subscription ARN: {response.get('SubscriptionArn', 'N/A')}")
            print("Please note: This subscription will be pending confirmation until the endpoint validates it.")
        except Exception as e:
            print(f"Error creating subscription for {endpoint}: {e}")

if __name__ == "__main__":
    manage_sns_subscriptions()